// 把不同入口（LINE / 表單）的欄位，統一映射成 backend /sop-pending 的 body。
// 欄位：name(標題), md(內容), submitter, type(SOP|FAQ|Ref), op(new|modify|delete), source.
const b = $input.first().json.body || $input.first().json;
return [{ json: {
  name: b.title || b.name || '',
  md: b.md || b.content || '',
  submitter: b.submitter || b.user || '匿名',
  type: b.type || 'SOP',
  op: b.op || 'new',
  source: b.source || 'n8n',
  reason: b.reason || ''
} }];
